function initMenu(){let t=document.getElementById("nav-toggle"),o=document.getElementById("nav-menu");var e=document.querySelectorAll(".nav__menu a");t&&o&&(t.addEventListener("click",()=>{o.classList.toggle("show-menu"),t.classList.toggle("show-icon")}),e.forEach(e=>{e.addEventListener("click",()=>{o.classList.remove("show-menu"),t.classList.remove("show-icon")})}))}function initCursorFollower(){if(window.matchMedia("(min-width: 1024px)").matches&&window.matchMedia("(hover: hover)").matches){let i=document.querySelector(".cursor-follower");if(i){let t=0,o=0,n=0,c=0;document.addEventListener("mousemove",e=>{t=e.clientX,o=e.clientY}),!function e(){n+=.15*(t-n),c+=.15*(o-c),i.style.left=n+"px",i.style.top=c+"px",requestAnimationFrame(e)}(),document.querySelectorAll("[data-cursor-text]").forEach(e=>{e.addEventListener("mouseenter",()=>{i.classList.add("active"),i.dataset.text=e.dataset.cursorText||""}),e.addEventListener("mouseleave",()=>{i.classList.remove("active"),i.dataset.text=""})})}}}function initAccordion(){var e=document.querySelectorAll(".questions__item");if(e.length){let o=e=>{var t=e.querySelector(".questions__content");t&&(e.classList.contains("accordion-open")?(t.style.height="",e.classList.remove("accordion-open")):(t.style.height=t.scrollHeight+"px",e.classList.add("accordion-open")))};e.forEach(t=>{var e=t.querySelector(".questions__header");e&&e.addEventListener("click",()=>{var e=document.querySelector(".accordion-open");o(t),e&&e!==t&&o(e)})})}}function initScrollHeader(){let e=document.getElementById("header");var t;e&&((t=()=>{80<=window.scrollY?e.classList.add("scroll-header"):e.classList.remove("scroll-header")})(),window.addEventListener("scroll",t))}document.addEventListener("DOMContentLoaded",()=>{initMenu(),initCursorFollower(),initAccordion(),initScrollHeader()});